// class: IndexService
    private String extractFirstHeading(String text) {
        Matcher matcher = Pattern.compile("^#{1,4}\\s+(.+)$", Pattern.MULTILINE).matcher(text);
        return matcher.find() ? matcher.group(1).trim() : null;
    }

// class: RagChatService
    public ChatResult chat(String userQuestion) {
        log.info("收到用户提问：{}", userQuestion);

        // 1. 向量化用户问题
        Embedding queryEmbedding = embeddingModel.embed(userQuestion).content();

        // 2. 向量相似度检索 Top-K
        List<EmbeddingMatch<TextSegment>> vectorMatches = embeddingStore.findRelevant(queryEmbedding, VECTOR_TOP_K,
                MIN_SCORE);
        log.info("向量检索命中 {} 个片段", vectorMatches.size());

        // 3. 关键字检索（精确匹配类名/方法名/文件路径/代码内容）
        List<TextSegment> keywordMatches = keywordSearch(userQuestion, KEYWORD_TOP_K);
        log.info("关键字检索命中 {} 个片段", keywordMatches.size());

        // 4. 合并两路结果，用 Set 去重（以 segment text 为 key）
        Map<String, TextSegment> mergedMap = new LinkedHashMap<>();
        // 向量检索结果优先
        for (EmbeddingMatch<TextSegment> m : vectorMatches) {
            mergedMap.putIfAbsent(m.embedded().text(), m.embedded());
        }
        // 关键字结果补充
        for (TextSegment seg : keywordMatches) {
            mergedMap.putIfAbsent(seg.text(), seg);
        }
        List<TextSegment> mergedSegments = new ArrayList<>(mergedMap.values());
        log.info("合并后共 {} 个唯一片段", mergedSegments.size());

        // 5. 构建上下文字符串（带来源标注）
        String context = buildContext(mergedSegments, vectorMatches);

        // 6. 提取来源信息
        List<String> sources = mergedSegments.stream()
                .map(seg -> {
                    String source = seg.metadata().getString("source");
                    if ("code".equals(source))
                        return seg.metadata().getString("path");
                    return "Project-Blueprint.md";
                })
                .filter(Objects::nonNull)
                .distinct()
                .toList();

        // 7. 构建增强 Prompt
        String augmentedPrompt = String.format("""
                %s

                ## 检索到的上下文信息

                %s

                ## 用户问题

                %s

                请基于以上上下文信息，给出准确、专业的回答。
                """, SYSTEM_PROMPT, context, userQuestion);

        // 8. 调用 LLM 生成回答
        String answer = chatModel.generate(augmentedPrompt);

        log.info("RAG 回答生成完毕，引用 {} 个来源", sources.size());
        return new ChatResult(answer, sources);
    }

// class: RagChatService
    private String buildContext(List<TextSegment> segments, List<EmbeddingMatch<TextSegment>> vectorMatches) {
        // 建立 text -> score 映射（向量检索有相似度分数）
        Map<String, Double> scoreMap = vectorMatches.stream()
                .collect(Collectors.toMap(
                        m -> m.embedded().text(),
                        EmbeddingMatch::score,
                        (a, b) -> a));

        return segments.stream()
                .map(seg -> {
                    String source = seg.metadata().getString("source");
                    String prefix;
                    if ("blueprint".equals(source)) {
                        String title = seg.metadata().getString("title");
                        prefix = title != null ? "[审计报告 - " + title + "]" : "[审计报告]";
                    } else {
                        String path = seg.metadata().getString("path");
                        String className = seg.metadata().getString("className");
                        String methodName = seg.metadata().getString("methodName");
                        String startLine = seg.metadata().getString("startLine");
                        String endLine = seg.metadata().getString("endLine");
                        // 构建精确定位标注：文件路径 + 类名 + 方法名 + 行号范围
                        StringBuilder prefixSb = new StringBuilder("[代码: ");
                        if (path != null)
                            prefixSb.append(path);
                        if (className != null)
                            prefixSb.append(" | 类: ").append(className);
                        if (methodName != null)
                            prefixSb.append(" | 方法: ").append(methodName);
                        if (startLine != null && endLine != null) {
                            prefixSb.append(" | L").append(startLine).append("-").append(endLine);
                        }
                        prefixSb.append("]");
                        prefix = prefixSb.toString();
                    }
                    // 如果有向量检索分数则展示出来
                    Double score = scoreMap.get(seg.text());
                    String scoreStr = score != null ? " (相似度: " + String.format("%.2f", score) + ")" : " (关键字匹配)";
                    return prefix + scoreStr + "\n" + seg.text();
                })
                .collect(Collectors.joining("\n\n---\n\n"));
    }

// class: RagChatService
    public record ChatResult(String answer, List<String> sources) {
    }

package com.bupt.cqy.analyzer.service;

import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;

@Slf4j
@Service
public class ProjectSummarizerService {

    public void saveBlueprint(String auditReport, String outputPath) throws IOException {
        Path path = Paths.get(outputPath, "Project-Blueprint.md");
        Files.writeString(path, auditReport);
        log.info("Blueprint saved to: {}", path.toAbsolutePath());
    }
}

package com.bupt.cqy.analyzer.service;

import com.bupt.cqy.analyzer.model.Document;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.util.List;
import java.util.Set;
import java.util.concurrent.CopyOnWriteArrayList;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.TimeUnit;
import java.util.stream.Stream;

@Service
public class FileCrawlerService {

    private static final Set<String> SUPPORTED_EXTENSIONS = Set.of(".java", ".py", ".cpp", ".js");

    public List<Document> crawl(String rootDir) throws IOException, InterruptedException {
        List<Document> documents = new CopyOnWriteArrayList<>();

        try (Stream<Path> paths = Files.walk(Path.of(rootDir))) {
            List<Path> files = paths
                    .filter(Files::isRegularFile)
                    .filter(p -> SUPPORTED_EXTENSIONS.stream().anyMatch(p.toString()::endsWith))
                    .toList();

            ExecutorService executor = Executors.newCachedThreadPool();
            for (Path file : files) {
                executor.submit(() -> {
                    try {
                        String content = Files.readString(file);
                        String ext = file.toString().substring(file.toString().lastIndexOf('.'));
                        documents.add(new Document(file.toString(), content, ext));
                    } catch (IOException e) {
                        // skip unreadable files
                    }
                });
            }
            executor.shutdown();
            executor.awaitTermination(60, TimeUnit.SECONDS);
        }

        return documents;
    }
}

package com.bupt.cqy.analyzer.service;

import com.bupt.cqy.analyzer.model.CodeSnippet;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;

@Slf4j
@Service
@RequiredArgsConstructor
public class LogicAuditService {

    private final AuditAssistant auditAssistant;

    public String auditProject(List<CodeSnippet> snippets) {
        log.info("Starting logic audit for {} code snippets", snippets.size());

        StringBuilder projectData = new StringBuilder();
        projectData.append("# Project Analysis Data\n\n");
        projectData.append("## Metadata\n");
        projectData.append("- Total Files: ").append(snippets.size()).append("\n");
        projectData.append("- Languages: ");

        long javaCount = snippets.stream().filter(s -> "Java".equals(s.getLanguage())).count();
        long pythonCount = snippets.stream().filter(s -> "Python".equals(s.getLanguage())).count();
        long cppCount = snippets.stream().filter(s -> "C++".equals(s.getLanguage())).count();
        long goCount = snippets.stream().filter(s -> "Go".equals(s.getLanguage())).count();

        projectData.append(String.format("Java(%d), Python(%d), C++(%d), Go(%d)\n\n",
                javaCount, pythonCount, cppCount, goCount));

        projectData.append("## File List and Code Content\n\n");

        for (CodeSnippet snippet : snippets) {
            projectData.append("### File: ").append(snippet.getPath()).append("\n");
            projectData.append("**Language**: ").append(snippet.getLanguage()).append("\n\n");
            projectData.append("```").append(snippet.getLanguage().toLowerCase()).append("\n");
            projectData.append(snippet.getCode()).append("\n");
            projectData.append("```\n\n");
        }

        String analysisInput = projectData.toString();
        log.info("Sending {} characters to DeepSeek for analysis", analysisInput.length());

        String report = auditAssistant.analyzeLogic(analysisInput);

        log.info("Audit completed, report generated");
        return report;
    }

    public String analyzeCodeSnippet(CodeSnippet snippet) {
        log.info("Analyzing single code snippet: {}", snippet.getPath());

        String input = String.format("""
                # Single File Analysis

                **File**: %s
                **Language**: %s

                ```%s
                %s
                ```

                Please provide a focused analysis of this file, highlighting any issues and improvement suggestions.
                """,
                snippet.getPath(),
                snippet.getLanguage(),
                snippet.getLanguage().toLowerCase(),
                snippet.getCode());

        return auditAssistant.analyzeLogic(input);
    }
}

package com.bupt.cqy.analyzer.config;

import dev.langchain4j.data.segment.TextSegment;
import dev.langchain4j.model.embedding.EmbeddingModel;
import dev.langchain4j.model.embedding.onnx.bgesmallzhv15q.BgeSmallZhV15QuantizedEmbeddingModel;
