import java.nio.file.Files;
import java.nio.file.Path;

@Slf4j
@Configuration
public class VectorStoreConfig {

    /**
     * 向量库持久化文件路径，可在 application.properties 中配置：
     * rag.vector-store.persist-path=./data/vector-store.json
     */
    @Value("${rag.vector-store.persist-path:./data/vector-store.json}")
    private String persistPath;

    private InMemoryEmbeddingStore<TextSegment> store;

    /**
     * 嵌入模型：bge-small-zh-v1.5（量化版）
     * - 来源：BAAI（北京智源人工智能研究院）
     * - 维度：512 维
     * - 大小：~25MB（量化后），本地 ONNX 推理，零网络依赖
     * - 优势：vs AllMiniLmL6V2（英文384维），在中文代码注释 + 中文问答场景下语义召回更准确
     */
    @Bean
    public EmbeddingModel embeddingModel() {
        return new BgeSmallZhV15QuantizedEmbeddingModel();
    }

    /**
     * 向量库：启动时从文件加载，关闭时持久化到文件。
     * 避免每次重启后必须重新跑 /api/analyze。
     */
    @Bean
    public EmbeddingStore<TextSegment> embeddingStore() {
        Path path = Path.of(persistPath);
        if (Files.exists(path)) {
            try {
                store = InMemoryEmbeddingStore.fromFile(path);
                log.info("向量库从持久化文件加载完成：{}", path.toAbsolutePath());
                return store;
            } catch (Exception e) {
                log.warn("向量库文件加载失败，将创建新的空向量库。原因: {}", e.getMessage());
            }
        } else {
            log.info("未找到持久化文件，创建新的空向量库。首次使用请调用 /api/analyze 建立索引。");
        }
        store = new InMemoryEmbeddingStore<>();
        return store;
    }

    /**
     * 主动持久化向量库（可在索引完成后立即调用，保证数据安全）。
     * 同时通过 @PreDestroy 在应用关闭时兜底调用一次。
     */
    public void persist() {
        if (store == null)
            return;
        try {
            Path path = Path.of(persistPath);
            Files.createDirectories(path.getParent());
            store.serializeToFile(path);
            log.info("向量库已持久化到：{}", path.toAbsolutePath());
        } catch (Exception e) {
            log.error("向量库持久化失败: {}", e.getMessage(), e);
        }
    }

    @PreDestroy
    public void persistStore() {
        persist();
    }
}

// class: AnalysisController
    public ResponseEntity<Map<String, Object>> analyzeProject(@RequestParam String path) {
        log.info("Received analysis request for path: {}", path);

        try {
            // Step 1: Scan project
            log.info("Step 1: Scanning project...");
            List<CodeSnippet> snippets = codeCrawlerService.scanProject(path);

            if (snippets.isEmpty()) {
                return ResponseEntity.badRequest()
                        .body(Map.of("error", "No supported code files found in the specified path"));
            }

            // Step 2: Perform logic audit
            log.info("Step 2: Performing logic audit...");
            String auditReport = logicAuditService.auditProject(snippets);

            // Step 3: Save blueprint
            log.info("Step 3: Saving project blueprint...");
            projectSummarizerService.saveBlueprint(auditReport, path);

            // Step 4: 向量化索引（RAG 联动）
            log.info("Step 4: Indexing for RAG...");
            indexService.indexAll(auditReport, snippets);

            // Step 5: 立即持久化向量库，防止重启丢失
            log.info("Step 5: Persisting vector store...");
            vectorStoreConfig.persist();

            // Build response
            Map<String, Object> response = new HashMap<>();
            response.put("status", "success");
            response.put("filesScanned", snippets.size());
            response.put("auditReport", auditReport);
            response.put("blueprint", auditReport);
            response.put("message", "Analysis completed successfully. Blueprint saved and indexed for RAG.");

            log.info("Analysis completed successfully for path: {}", path);
            return ResponseEntity.ok(response);

        } catch (Exception e) {
            log.error("Analysis failed for path: {}", path, e);
            Map<String, Object> errorResponse = new HashMap<>();
            errorResponse.put("status", "error");
            errorResponse.put("message", e.getMessage());
            return ResponseEntity.internalServerError().body(errorResponse);
        }
    }

